import { Component, Element, h, Listen, Prop, State } from '@stencil/core';
import { CountdownVariant } from './wdpr-time-unit/wdpr-time-unit.model';
import { customTwMerge } from '../../utils/utils';

@Component({
  tag: 'wdpr-detailed-countdown-timer',
  shadow: true,
})
export class WdprDetailedCountdownTimer {
  private _endDate: Date;

  @Element() el: HTMLWdprDetailedCountdownTimerElement;

  @Prop() endAt: number;
  @Prop() type: 'inline' | 'stacked' = 'inline';
  @Prop() variant: CountdownVariant = 'primary';

  @State() _hours: string = '##';
  @State() _minutes: string = '##';
  @State() _seconds: string = '##';
  @State() hasDayDigit1: boolean = false;
  @State() hasDayDigit2: boolean = false;
  @State() hasDayDigit3: boolean = false;
  /**
   * @internal
   * Whether the countdown is being rendered in mobile view.
   * Computed from viewport width (<768px).
   * @type {boolean}
   */
  @State() _isMobileView: boolean = false;

  @Listen('resize', { target: 'window' })
  handleResize() {
    const viewportWidth = window.innerWidth;
    this._isMobileView = viewportWidth < 768;
  }

  componentWillLoad() {
    if (!this.endAt) return;

    this._endDate = new Date(this.endAt);

    this._tick();
  }

  private _tick() {
    const now = Date.now();
    const timeRemaining = this._endDate.getTime() - now;

    if (timeRemaining <= 0) {
      this._hours = this._minutes = this._seconds = '00';

      return;
    }

    const hours = Math.floor((timeRemaining % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
    const minutes = Math.floor((timeRemaining % (1000 * 60 * 60)) / (1000 * 60));
    const seconds = Math.floor((timeRemaining % (1000 * 60)) / 1000);

    this._hours = String(hours).padStart(2, '0');
    this._minutes = String(minutes).padStart(2, '0');
    this._seconds = String(seconds).padStart(2, '0');

    setTimeout(() => this._tick(), 1000);
  }

  private _renderColon(isStacked: boolean = false) {
    const sizeClasses = 'w-[3px] h-[44px]';
    const inlineClasses = 'flex flex-col justify-center items-center';
    const colorClasses = 'text-text-inverse';

    const colonClasses = customTwMerge(sizeClasses, !isStacked && inlineClasses, colorClasses);

    return <span class={colonClasses}>:</span>;
  }

  render() {
    const isStacked = this._isMobileView || this.type === 'stacked';
    const hourDigits = this._hours.split('');
    const minuteDigits = this._minutes.split('');
    const secondDigits = this._seconds.split('');

    const hasDayDigit1 = !!this.el.querySelector('[slot="day-digit-1"]');
    const hasDayDigit2 = !!this.el.querySelector('[slot="day-digit-2"]');
    const hasDayDigit3 = !!this.el.querySelector('[slot="day-digit-3"]');

    const hasHourDigit1 = !!this.el.querySelector('[slot="hour-digit-1"]');
    const hasHourDigit2 = !!this.el.querySelector('[slot="hour-digit-2"]');

    const hasMinuteDigit1 = !!this.el.querySelector('[slot="minute-digit-1"]');
    const hasMinuteDigit2 = !!this.el.querySelector('[slot="minute-digit-2"]');

    const hasSecondDigit1 = !!this.el.querySelector('[slot="second-digit-1"]');
    const hasSecondDigit2 = !!this.el.querySelector('[slot="second-digit-2"]');

    return (
      <div class={isStacked ? 'flex flex-col items-center gap-100' : 'flex items-center gap-050'}>
        <wdpr-day-countdown-timer size={isStacked ? 'large' : 'small'} endAt={this.endAt} variant={this.variant}>
          {hasDayDigit1 && <slot name="day-digit-1" slot="day-digit-1"></slot>}
          {hasDayDigit2 && <slot name="day-digit-2" slot="day-digit-2"></slot>}
          {hasDayDigit3 && <slot name="day-digit-3" slot="day-digit-3"></slot>}
        </wdpr-day-countdown-timer>

        <div class={isStacked ? 'flex items-center gap-050' : 'flex gap-050'}>
          {!isStacked && this._renderColon(isStacked)}

          <wdpr-time-unit label="Hours" digits={[hourDigits[0], hourDigits[1]]} slotPrefix="hour" variant={this.variant}>
            {hasHourDigit1 && <slot name="hour-digit-1" slot="hour-digit-1"></slot>}
            {hasHourDigit2 && <slot name="hour-digit-2" slot="hour-digit-2"></slot>}
          </wdpr-time-unit>

          {this._renderColon(isStacked)}

          <wdpr-time-unit label="Mins" digits={[minuteDigits[0], minuteDigits[1]]} slotPrefix="minute" variant={this.variant}>
            {hasMinuteDigit1 && <slot name="minute-digit-1" slot="minute-digit-1"></slot>}
            {hasMinuteDigit2 && <slot name="minute-digit-2" slot="minute-digit-2"></slot>}
          </wdpr-time-unit>

          {this._renderColon(isStacked)}

          <wdpr-time-unit label="Secs" digits={[secondDigits[0], secondDigits[1]]} slotPrefix="second" variant={this.variant}>
            {hasSecondDigit1 && <slot name="second-digit-1" slot="second-digit-1"></slot>}
            {hasSecondDigit2 && <slot name="second-digit-2" slot="second-digit-2"></slot>}
          </wdpr-time-unit>
        </div>
      </div>
    );
  }
}
